<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu-ish Desktop</title>
<style>
  * { box-sizing: border-box; }
  html, body {
    margin: 0; padding: 0; width: 100%; height: 100%;
    font-family: "Segoe UI", Ubuntu, -apple-system, sans-serif;
    overflow: hidden;
    user-select: none;
  }

  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(160deg, #2c0b3f 0%, #4b1248 35%, #772953 70%, #aa3e5c 100%);
    overflow: hidden;
  }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20, 10, 25, 0.85);
    color: #eee;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 13px;
    letter-spacing: 0.5px;
    z-index: 5000;
    border-bottom: 1px solid rgba(255,255,255,0.08);
  }

  /* Dock / Taskbar */
  #taskbar {
    position: absolute;
    left: 0; top: 28px; bottom: 0;
    width: 64px;
    background: rgba(20, 10, 25, 0.75);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 10px;
    z-index: 4000;
    border-right: 1px solid rgba(255,255,255,0.06);
  }

  .launcher {
    width: 46px; height: 46px;
    border-radius: 12px;
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.1);
    display: flex; align-items: center; justify-content: center;
    font-size: 22px;
    cursor: pointer;
    color: #fff;
    transition: background 0.15s, transform 0.1s;
  }
  .launcher:hover {
    background: rgba(255,255,255,0.2);
    transform: scale(1.05);
  }
  .launcher:active { transform: scale(0.96); }

  /* Desktop icons area (decoration only) */
  .desktop-icon {
    position: absolute;
    top: 50px;
    width: 80px;
    text-align: center;
    color: #fff;
    font-size: 12px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.6);
    pointer-events: none;
    opacity: 0.85;
  }
  .desktop-icon .glyph { font-size: 32px; display: block; margin-bottom: 4px; }

  /* Windows */
  .app-window {
    position: absolute;
    top: 70px; left: 110px;
    width: 620px; height: 420px;
    min-width: 360px; min-height: 240px;
    background: #2d2d2d;
    border-radius: 8px;
    box-shadow: 0 20px 60px rgba(0,0,0,0.5);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
    border: 1px solid rgba(255,255,255,0.08);
  }
  .app-window.open { display: flex; }
  .app-window.active { z-index: 500; }

  #notepad-window { left: 220px; top: 110px; }

  .win-titlebar {
    height: 36px;
    background: #3a3a3a;
    display: flex;
    align-items: center;
    padding: 0 8px;
    cursor: move;
    color: #eee;
    font-size: 13px;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    flex-shrink: 0;
  }
  .win-titlebar .title { flex: 1; padding-left: 6px; }
  .win-controls { display: flex; gap: 6px; }
  .win-btn {
    width: 14px; height: 14px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 9px;
    color: transparent;
  }
  .win-close { background: #ff5f56; }
  .win-close:hover { color: #4a0000; }
  .win-min { background: #ffbd2e; }
  .win-max { background: #27c93f; }

  .win-body {
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    background: #252525;
    color: #eee;
  }

  /* Files App */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    background: #333;
    border-bottom: 1px solid #444;
    flex-shrink: 0;
  }
  #files-up {
    background: #4a4a4a;
    border: 1px solid #5a5a5a;
    color: #eee;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
    font-size: 12px;
  }
  #files-up:hover { background: #5a5a5a; }
  #files-path {
    background: #1e1e1e;
    border: 1px solid #444;
    border-radius: 4px;
    padding: 4px 10px;
    font-family: monospace;
    font-size: 12px;
    flex: 1;
    color: #9fd3ff;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  #files-listing {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 4px;
  }
  .fs-item {
    width: 84px;
    padding: 8px 4px;
    text-align: center;
    border-radius: 6px;
    cursor: default;
    font-size: 12px;
    color: #eee;
    word-break: break-word;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(80,150,255,0.35); }
  .fs-item .icon { font-size: 28px; display: block; margin-bottom: 4px; }

  /* Notepad App */
  #tabs {
    display: flex;
    background: #333;
    border-bottom: 1px solid #444;
    flex-shrink: 0;
    overflow-x: auto;
  }
  .tab {
    padding: 8px 14px;
    font-size: 12px;
    color: #ccc;
    cursor: pointer;
    border-right: 1px solid #444;
    white-space: nowrap;
    display: flex;
    align-items: center;
    gap: 8px;
    background: #2a2a2a;
  }
  .tab.active { background: #252525; color: #fff; border-top: 2px solid #e95420; }
  .tab .tab-close {
    font-size: 12px;
    color: #999;
    line-height: 1;
    padding: 0 3px;
    border-radius: 3px;
  }
  .tab .tab-close:hover { background: #555; color: #fff; }
  #new-tab {
    padding: 8px 12px;
    background: #2a2a2a;
    color: #ccc;
    cursor: pointer;
    font-size: 16px;
    line-height: 1;
    flex-shrink: 0;
  }
  #new-tab:hover { background: #3a3a3a; }
  #editor {
    flex: 1;
    resize: none;
    border: none;
    outline: none;
    background: #1e1e1e;
    color: #eee;
    font-family: "Cascadia Code", Consolas, monospace;
    font-size: 14px;
    padding: 12px;
    line-height: 1.5;
  }
</style>
</head>
<body>

<div id="desktop">
  <div id="topbar">Activities &nbsp;•&nbsp; Ubuntu-ish Desktop</div>

  <div class="desktop-icon" style="left: 90px;">
    <span class="glyph">🗂️</span>Files
  </div>
  <div class="desktop-icon" style="left: 90px; top: 150px;">
    <span class="glyph">📝</span>Notepad
  </div>

  <div id="taskbar">
    <div class="launcher" id="open-files" title="Files">🗂️</div>
    <div class="launcher" id="open-notepad" title="Notepad">📝</div>
  </div>

  <!-- Files Window -->
  <div class="app-window" id="files-window">
    <div class="win-titlebar" data-target="files-window">
      <div class="win-controls">
        <button class="win-btn win-close" data-target="files-window">×</button>
        <button class="win-btn win-min">–</button>
        <button class="win-btn win-max">▢</button>
      </div>
      <div class="title">Files</div>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div class="app-window" id="notepad-window">
    <div class="win-titlebar" data-target="notepad-window">
      <div class="win-controls">
        <button class="win-btn win-close" data-target="notepad-window">×</button>
        <button class="win-btn win-min">–</button>
        <button class="win-btn win-max">▢</button>
      </div>
      <div class="title">Notepad</div>
    </div>
    <div class="win-body">
      <div id="tabs">
        <div id="new-tab" title="New tab">+</div>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ---------------------------------------------------------
     Window management (open/close/drag/focus)
  --------------------------------------------------------- */
  var windows = document.querySelectorAll(".app-window");
  var zCounter = 500;

  function bringToFront(win) {
    windows.forEach(function (w) { w.classList.remove("active"); });
    zCounter += 1;
    win.style.zIndex = zCounter;
    win.classList.add("active");
  }

  function openWindow(id) {
    var win = document.getElementById(id);
    win.classList.add("open");
    bringToFront(win);
  }

  function closeWindow(win) {
    win.classList.remove("open");
  }

  document.getElementById("open-files").addEventListener("click", function () {
    openWindow("files-window");
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    openWindow("notepad-window");
    renderTabs();
    renderEditor();
  });

  document.querySelectorAll(".win-close").forEach(function (btn) {
    btn.addEventListener("click", function (e) {
      e.stopPropagation();
      var target = document.getElementById(btn.getAttribute("data-target"));
      closeWindow(target);
    });
  });

  windows.forEach(function (win) {
    win.addEventListener("mousedown", function () {
      bringToFront(win);
    });
  });

  /* Dragging via titlebar */
  (function enableDragging() {
    var dragState = null;

    document.querySelectorAll(".win-titlebar").forEach(function (bar) {
      bar.addEventListener("mousedown", function (e) {
        if (e.target.classList.contains("win-btn")) return;
        var win = document.getElementById(bar.getAttribute("data-target"));
        bringToFront(win);
        var rect = win.getBoundingClientRect();
        var desktopRect = document.getElementById("desktop").getBoundingClientRect();
        dragState = {
          win: win,
          offsetX: e.clientX - rect.left,
          offsetY: e.clientY - rect.top,
          desktopRect: desktopRect
        };
        e.preventDefault();
      });
    });

    document.addEventListener("mousemove", function (e) {
      if (!dragState) return;
      var x = e.clientX - dragState.desktopRect.left - dragState.offsetX;
      var y = e.clientY - dragState.desktopRect.top - dragState.offsetY;
      x = Math.max(0, x);
      y = Math.max(0, y);
      dragState.win.style.left = x + "px";
      dragState.win.style.top = y + "px";
    });

    document.addEventListener("mouseup", function () {
      dragState = null;
    });
  })();

  /* ---------------------------------------------------------
     Files App — static fake filesystem
  --------------------------------------------------------- */
  var FS = {
    name: "/",
    type: "folder",
    children: [
      {
        name: "bin", type: "folder", children: [
          { name: "bash", type: "file" },
          { name: "ls", type: "file" },
          { name: "cat", type: "file" }
        ]
      },
      {
        name: "etc", type: "folder", children: [
          { name: "hostname", type: "file" },
          { name: "passwd", type: "file" },
          { name: "fstab", type: "file" }
        ]
      },
      {
        name: "home", type: "folder", children: [
          {
            name: "user", type: "folder", children: [
              {
                name: "Documents", type: "folder", children: [
                  { name: "resume.txt", type: "file" },
                  { name: "notes.md", type: "file" }
                ]
              },
              {
                name: "Downloads", type: "folder", children: [
                  { name: "installer.deb", type: "file" }
                ]
              },
              {
                name: "Pictures", type: "folder", children: [
                  { name: "wallpaper.png", type: "file" },
                  { name: "vacation.jpg", type: "file" }
                ]
              },
              { name: ".bashrc", type: "file" },
              { name: "todo.txt", type: "file" }
            ]
          }
        ]
      },
      {
        name: "usr", type: "folder", children: [
          {
            name: "local", type: "folder", children: [
              { name: "bin", type: "folder", children: [] }
            ]
          },
          {
            name: "share", type: "folder", children: [
              { name: "doc", type: "folder", children: [] }
            ]
          }
        ]
      },
      {
        name: "var", type: "folder", children: [
          {
            name: "log", type: "folder", children: [
              { name: "syslog", type: "file" },
              { name: "auth.log", type: "file" }
            ]
          },
          { name: "tmp", type: "folder", children: [] }
        ]
      }
    ]
  };

  var currentPath = []; // array of names, e.g. ["home", "user"]

  function resolvePath(pathArr) {
    var node = FS;
    for (var i = 0; i < pathArr.length; i++) {
      var name = pathArr[i];
      var next = null;
      for (var j = 0; j < node.children.length; j++) {
        if (node.children[j].name === name && node.children[j].type === "folder") {
          next = node.children[j];
          break;
        }
      }
      if (!next) return FS;
      node = next;
    }
    return node;
  }

  function renderFiles() {
    var node = resolvePath(currentPath);
    var pathStr = "/" + currentPath.join("/");
    document.getElementById("files-path").textContent = pathStr === "/" ? "/" : pathStr;

    var listing = document.getElementById("files-listing");
    listing.innerHTML = "";

    var items = node.children.slice().sort(function (a, b) {
      if (a.type !== b.type) return a.type === "folder" ? -1 : 1;
      return a.name.localeCompare(b.name);
    });

    items.forEach(function (item) {
      var el = document.createElement("div");
      el.className = "fs-item";
      el.setAttribute("data-type", item.type);
      var icon = item.type === "folder" ? "📁" : "📄";
      el.innerHTML = '<span class="icon">' + icon + '</span>' + escapeHtml(item.name);

      el.addEventListener("click", function () {
        document.querySelectorAll(".fs-item.selected").forEach(function (s) {
          s.classList.remove("selected");
        });
        el.classList.add("selected");
      });

      el.addEventListener("dblclick", function () {
        if (item.type === "folder") {
          currentPath.push(item.name);
          renderFiles();
        }
      });

      listing.appendChild(el);
    });
  }

  function escapeHtml(str) {
    var div = document.createElement("div");
    div.textContent = str;
    return div.innerHTML;
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ---------------------------------------------------------
     Notepad App — tabbed, persistent via localStorage
  --------------------------------------------------------- */
  var STORAGE_KEY = "ubuntu-desktop-notepad-state";
  var notepadState = loadNotepadState();

  function loadNotepadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          return parsed;
        }
      }
    } catch (e) { /* ignore corrupt storage */ }
    return {
      tabs: [{ id: genId(), title: "untitled.txt", content: "" }],
      activeId: null
    };
  }

  function genId() {
    return "t" + Math.floor((Math.random ? Math.random() : 0.5) * 1e9).toString(36) + Date.now().toString(36).slice(-4);
  }

  // Ensure activeId is valid
  if (!notepadState.activeId || !notepadState.tabs.some(function (t) { return t.id === notepadState.activeId; })) {
    notepadState.activeId = notepadState.tabs[0].id;
  }

  function saveNotepadState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadState));
  }

  function getActiveTab() {
    return notepadState.tabs.find(function (t) { return t.id === notepadState.activeId; });
  }

  function renderTabs() {
    var tabsEl = document.getElementById("tabs");
    // Remove existing .tab elements (keep #new-tab)
    tabsEl.querySelectorAll(".tab").forEach(function (t) { t.remove(); });

    notepadState.tabs.forEach(function (tab) {
      var tabEl = document.createElement("div");
      tabEl.className = "tab" + (tab.id === notepadState.activeId ? " active" : "");
      tabEl.setAttribute("data-id", tab.id);

      var titleSpan = document.createElement("span");
      titleSpan.className = "tab-title";
      titleSpan.textContent = tab.title || "untitled.txt";
      tabEl.appendChild(titleSpan);

      var closeSpan = document.createElement("span");
      closeSpan.className = "tab-close";
      closeSpan.textContent = "×";
      closeSpan.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(tab.id);
      });
      tabEl.appendChild(closeSpan);

      tabEl.addEventListener("click", function () {
        notepadState.activeId = tab.id;
        saveNotepadState();
        renderTabs();
        renderEditor();
      });

      tabsEl.insertBefore(tabEl, document.getElementById("new-tab"));
    });
  }

  function renderEditor() {
    var editor = document.getElementById("editor");
    var active = getActiveTab();
    editor.value = active ? active.content : "";
  }

  document.getElementById("editor").addEventListener("input", function (e) {
    var active = getActiveTab();
    if (active) {
      active.content = e.target.value;
      saveNotepadState();
    }
  });

  document.getElementById("new-tab").addEventListener("click", function () {
    var newTab = { id: genId(), title: "untitled.txt", content: "" };
    notepadState.tabs.push(newTab);
    notepadState.activeId = newTab.id;
    saveNotepadState();
    renderTabs();
    renderEditor();
  });

  function closeTab(id) {
    var idx = notepadState.tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    notepadState.tabs.splice(idx, 1);

    if (notepadState.tabs.length === 0) {
      var fresh = { id: genId(), title: "untitled.txt", content: "" };
      notepadState.tabs.push(fresh);
      notepadState.activeId = fresh.id;
    } else if (notepadState.activeId === id) {
      var newIdx = Math.max(0, idx - 1);
      notepadState.activeId = notepadState.tabs[newIdx].id;
    }
    saveNotepadState();
    renderTabs();
    renderEditor();
  }

  // Initial render (in case notepad is opened later, still populate now)
  renderTabs();
  renderEditor();
  saveNotepadState();
})();
</script>
</body>
</html>
